def bi(n,k):
    MIN=0
    MAX=n

    while MAX>MIN+1:
        bn=(MIN+MAX)//2
        if math.log2(k+2+bn)<bn+1:
            MAX=bn
        elif math.log2(k+2+bn)==bn+1:
            return bn
        else:
            MIN=bn

    if MAX+1<=math.log2(k+2+MAX):
        return MAX

    return MIN

