class Point:

    def __init__(self, x, y):
        self.x = x
        self.y = y


class Vector:

    def __init__(self, start, end):
        self.x = end.x - start.x
        self.y = end.y - start.y

    def mult(self, a):
        return self.y * a.x - self.x * a.y

