def generate_47_arr():
	arr = []
	for digits in range(1, 4):
		arr += itertools.product("47", repeat=digits)
	for i in range(len(arr)):
		arr[i] = int("".join(list(arr[i])))
	arr.append(4444444444)
	return arr

