def mcheck(a, pairs):
    m = len(a[0])
    allm = 2 ** m - 1

    subs = {i: {i} for i in range(allm + 1)}

    for i in range(allm + 1):
        for j in range(i):
            if i | j == i:  # 11 1  10 1   00 0  01 1
                subs[i].add(j)

    mx = [max(aa) for aa in a]

    @prof
    def check(v):
        masks = {0: -1}
        done = [False] * (allm + 1)
        for i, aa in enumerate(a):
            if mx[i] < v:
                continue
            c = sum(1 << b for b in range(len(aa)) if aa[b] >= v)
            # if c == allm:
            #     pairs[v] = i, i
            #     return True
            if not done[c]:
                for cc in subs[c]:
                    if allm - cc in masks:
                        other = masks[allm - c]
                        pairs[v] = i, other
                        return True
                    masks[cc] = i
                    done[cc] = True
                # masks[c] = i
        # for ma, mb in itertools.combinations(masks, 2):
        #     if ma | mb == allm:
        #         pairs[v] = masks[ma], masks[mb]
        #         return True
        return False

    return check


