def normal_sum(N):
	return (N ** 2 + N) // 2

def sum(i, j):

	return normal_sum(j) - 1 - (normal_sum(i-1) - 1)



def bs_sum(start, end, k, n):
	# print(start, end, k, n)
	mid = (start+end) // 2

	if(n - sum(mid, k) >= mid):
		return bs_sum(start, mid - 1, k, n)
	if(n - sum(mid, k) < 0):
		return bs_sum(mid+1, end, k, n)

	return k-mid+2 if (n - sum(mid, k)) != 0 else k-mid+1


