def bin_search(n):
    if n==1:
        return 1
    l = 0;r = n;
    while(r - 1 > l):
#        print(l,r)
        mid = (l+r)//2

        val = mid*(mid+1)//2
        if val == n:
            return mid
        elif val > n:
            r = mid
        else:
            l = mid

    return l


