def binarySearch(lo, hi, m):
    ans = []
    while lo < hi:
        mid = lo + (hi-lo+1)//2
        x = check(mid, m)
        if x:
            lo = mid
            ans = [x[0]+1, x[1]+1]
        else:
            hi = mid-1
    mid = lo + (hi-lo+1)//2
    x = check(mid, m)
    if x:
        ans = [x[0]+1, x[1]+1]
    return ans
