def around(x, y, hor, ver, mtx):
    a, b, c, d = [math.inf]*4

    if x > 0: 
        a = hor[y][x - 1] * 2 + mtx[y][x - 1]

    if x < m - 1: 
        b = hor[y][x] * 2 + mtx[y][x + 1]

    if y > 0: 
        c = ver[y - 1][x] * 2 + mtx[y - 1][x]

    if y < n - 1: 
        d = ver[y][x] * 2 + mtx[y + 1][x]

    return min(a, b, c, d)


