import math

def Maxxor(l,r):
	if(l==r):
		return 0
	else:
		reflog=math.floor(math.log2(r))
		ref=2**reflog
		if(l<ref):
			return (2*ref)-1
		else:
			return Maxxor(l-ref,r-ref)

