        x,y = Ps[i][0] - Ps[0][0],Ps[i][1] - Ps[0][1]
        if (x == 0 and y == 0):continue
        x,y = x//gcd(x,y),y//gcd(x,y)
        if (x < 0):x *= -1;y *= -1
        if (x == 0):y = abs(y)
        if (x,y) != (p,q):
            not_same.append(Ps[i])

    if len(not_same) <= 1:
        print("YES")
        return 0

    if on_one_line(not_same):
        print("YES")
        return 0  

    p,q = P - Ps[1][0],Q - Ps[1][1]
    g = gcd(p,q)
    p //= g;q //= g
    if (p < 0):p *= -1;q *= -1
    elif (p == 0):q = abs(q) 

    not_same = []
    for i in range(n):
        x,y = Ps[i][0] - Ps[1][0],Ps[i][1] - Ps[1][1]
        if (x == 0 and y == 0):continue
        x,y = x//gcd(x,y),y//gcd(x,y)
        if (x < 0):x *= -1;y *= -1
        if (x == 0):y = abs(y)
        if (x,y) != (p,q):
            not_same.append(Ps[i])

    if len(not_same) <= 1:
        print("YES")
        return 0

    if on_one_line(not_same):
        print("YES")
        return 0  

    print("NO")
    return 0


