def is_colinear(a1,a2,a3):
    if a1 == a2 or a2 == a3 or a1 == a3:
        return True

    x1,y1 = a1
    x2,y2 = a2
    x3,y3 = a3

    if x1 == x2 or x1 == x3 or x2 == x3:
        return x1 == x2 == x3
    if y1 == y2 or y1 == y3 or y2 == y3:
        return y1 == y2 == y3
    return (y2 - y1) * (x3 - x1) == (y3 - y1) * (x2 - x1)

