                line2.append(i)
            else:
                ok *= is_on_line(a[line2[0]], a[line2[1]], a[i])
                if ok == 0:
                    break
    if ok:
        return 1
    line1 = []
    line2 = []
    ok = 1
    for i in range(n):
        if not is_on_line(a[0],a[2],a[i]):
            if len(line2) < 2:
