def numtostr(a):
    var=[]
    while a>0:

       if a%26==0:
          var.append("Z")
          a=a//26-1
       else:
          var.append(chr(a%26-1+ord("A")))
          a=a//26
    var.reverse()
    return "".join(var)

def strtonum(b):
    par=len(b)
    result=0
    for i in range(1,par):
        result+=(26**i)
    par=len(b)-1
    for elem in b:
        if par!=0:
             result+=((ord(elem)-ord("A"))*((26)**par))
        else:
            result += ((ord(elem) - ord("A"))+1)

        if par==0:
            break
        par -= 1
    return result

