import os,sys
from io import BytesIO,IOBase

def check(n,mid,path,cost,num):
    ans,poi,visi = [],[0]*n,[0]*n
    for i in range(n):
        if visi[i]:
            continue
        visi[i],st,st1 = 2,[i],[]
        while len(st):
            x,y = st[-1],path[st[-1]]
            if poi[x] == len(y):
                visi[x] = 1
                st1.append(st.pop())
            else:
                i,j = y[poi[x]],cost[st[-1]][poi[x]]
                poi[x] += 1
                if j <= mid:
                    continue
                if visi[i] == 2:
                    return -1
                if not visi[i]:
                    st.append(i)
                    visi[i] = 2
        ans += st1
    start = [0]*n
    for ind,i in enumerate(reversed(ans)):
        start[i] = ind
    poi,visi,fin = [0]*n,[0]*n,[]
    for i in range(n):
        if visi[i]:
            continue
        visi[i],st = 1,[i]
        while len(st):
            x,y = st[-1],path[st[-1]]
            if poi[x] == len(y):
                st.pop()
            else:
                i,j,k = y[poi[x]],cost[st[-1]][poi[x]],num[st[-1]][poi[x]]
                poi[x] += 1
                visi[i] = 1
                st.append(i)
                if start[i] < start[x] and j <= mid:
                    fin.append(k)
    return fin

def main():
    n,m = map(int,input().split())
    path = [[] for _ in range(n)]
    cost = [[] for _ in range(n)]
    num = [[] for _ in range(n)]
    for _ in range(m):
        u1,v1,c1 = map(int,input().split())
        path[u1-1].append(v1-1)
        cost[u1-1].append(c1)
        num[u1-1].append(_+1)
    hi,lo = 10**9,0
    while hi >= lo:
        mid = (hi+lo)//2
        z = check(n,mid,path,cost,num)
        if z == -1:
            lo = mid+1
        else:
            hi = mid-1
            ans = mid
            an = z
    print(ans,len(an))
    print(*an)

