def sol(X): 
    g = [[] for _ in range(n)]
    ny = [0]*n
    for a,b,c in abc:
        if c > X:
            g[a-1].append(b-1)
            ny[b-1] += 1
    seen = [0]*n
    q = deque()
    for i,x in enumerate(ny):
        if x==0: q.append(i); seen[i] = 1
    while q:
        v = q.popleft()
        for u in g[v]:
            if seen[u]: continue
            ny[u] -= 1
            if ny[u] == 0:
                q.append(u)
                seen[u]= 1
    return all(seen)

def sol2(X): 
    g = [[] for _ in range(n)]
    ny = [0]*n
    for a,b,c in abc:
        if c > X:
            g[a-1].append(b-1)
            ny[b-1] += 1
    tps = [-1]*n; T = 0
    seen = [0]*n
    q = deque()
    for i,x in enumerate(ny):
        if x==0: q.append(i); seen[i] = 1
    while q:
        v = q.popleft()
        tps[v] = T; T += 1
        for u in g[v]:
            if seen[u]: continue
            ny[u] -= 1
            if ny[u] == 0:
                q.append(u)
                seen[u]= 1
    return tps

