def sum_1 (n):
    s=n*(n+1)//2
    return s

def sum_2(s,e):
    if s<=1:
        return sum_1(e)
    return sum_1(e)-sum_1(s-1)

def mini_splitter(k,n):
    st=1
    end=k
    while st<end:
        mid=(st+end)//2
        s=sum_2(mid,k)
        if s==n:
            return k-mid+1
        elif s>n:
            st=mid+1
        else:
            end=mid
    return k-st+2

