n,m=map(lambda x:int(x), input().split())
A = []
for _ in range(n):
    scores = list(map(lambda x:int(x), input().split()))
    A.append(scores)

def solve(n,m,A):
    # O(31*( 5*n + 4**5 ))
    # all index from 0
    ans = ()
    nstats = 2**m
    def judge(finalScore):
        nonlocal ans
        seen = {}
        for i,scores in enumerate(A):
            sta = 0
            for e in scores:
                sta=sta*2+(e>=finalScore)
            # example [1,2,3,4,1], finalScore=3
            # sta = 0b00110
            seen[sta]=i

        for i in range(nstats):
            for j in range(nstats):
                if ((i|j) == nstats-1) and i in seen and j in seen:
                    ans = (seen[i], seen[j])
                    return True

        return False

    l=0
    r=2**31-1
    while l<r:
        m=l+(r-l)//2
        if not judge(m):
            r=m
        else:
            l=m+1
    # Highest score is l-1
    print(ans[0]+1,ans[1]+1) # answer index start from 1

solve(n,m,A)

def mypw2(deg):
    if (deg >= 1500) : return 2 ** 150
    # if (deg >= 60): return 10**18 * 20
    return 2 ** deg

def sol():
    n, k = map(int, input().split())
    if (k == 0):
        print("YES", n)
        return
    for side in range(1, n + 1):
        MIN = mypw2(side + 1) - side - 2
        MAX = mypw2(2 * n) - mypw2(2 * n - side + 1) + mypw2(side + 1) + mypw2(2 * n - 2 * side) - 2;
        MAX //= 3
        # MAX = (mypw2(2*n) - 1) // 3 - ((2**(2*n - 2 * side) - 1) // 3) * (2**(side + 1) - 1)
        # print(k, MIN, MAX)
        if (MIN <= k <= MAX):
            print("YES", n - side)
            return
    print("NO")

def main():
    t = int(input())
    for i in range(t):
        sol()

main()

