def Binary_Search(arr , n , x):
    l , r = 0 , n-1
    while l <= r :
        mid = l + (r - l )//2
        if arr[mid] == x :
            return mid+1
        elif arr[mid] > x :
            r = mid - 1
        else:
            l = mid + 1
    return r + 1


