                h = hash(cell[0], cell[1])

                if m[cell[0]][cell[1]] == "#":
                    if (not h in lookup):
                        lst.append(h)

                else: # . found
                    fail = True
                    break

            if not fail:
                for item in lst:
                    lookup[item] = True
                count -= len(lst)

    return "YES" if count == 0 else "NO"

